import{_ as a,o as e,c as t,j as r,a as o,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"土龙流","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/无暇武道/土龙流.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/无暇武道/土龙流.md"}'),p={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/无暇武道/土龙流.md"};function s(i,b,l,d,h,c){return e(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"土龙流",tabindex:"-1"},[o("土龙流 "),r("a",{class:"header-anchor",href:"#土龙流","aria-label":'Permalink to "土龙流"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"灵魂蓝调016")])])],-1),n('<h1 id="土龙流-1" tabindex="-1">土龙流 <a class="header-anchor" href="#土龙流-1" aria-label="Permalink to &quot;土龙流&quot;">​</a></h1><p>土龙流（Earth Dragon Style）<br> 土龙流以精细的思虑缓慢而稳定地打出一招一式，锤炼出压倒性的力量。学徒们忍受强化躯体的硬功锻炼，通过击打数小时的沙堆锻炼躯体、以钉板床来锻炼耐受等。这种训练将他们培养成了难以战胜的战士，他们可以承受致命的打击与不从之神或受诅者交战，以强力的双拳做出反击。</p><p>流派武器：土龙流风格硬桥硬马，大开大合，徒手攻击以膝击（专业：腿）和双手锤击（专业：拳）进行有力地打击，此流派也可以用长枪、棍、锤施展。<br> 流派盔甲：土龙流兼容所有盔甲。</p><p>·进入战斗场景后，人物需要立刻获得等同于【力量+耐力属性】值的土灵精气，土灵精气是驱动土龙流的燃料，来源于武者与世界的摩擦与引导。在规则上武者的[土灵精气]并非能量池，仅仅是一个计数器，用以支撑土龙流主动技艺的施展，若人物已经掌握土龙势，则人物每维持土龙势至回合结束时，每轮可立即恢复等同于已经消耗土灵精气数量的一半（取高，最少恢复1点）。精髓会在场景结束时清零。</p><p>精气熔流<br> 价格：C+1000<br> 当武者进入战斗场景后，若他脚踏大地（由岩石土壤组成的平面，混凝土楼层可能可以，但飞机卡车或者类似的载具上不行）且土灵精气不为0，则他的土元之力会不受控制地溢出，化为纯粹的破坏力，被称为精气熔流。<br> 土元之力会本能的带动周身的大地震动，使得碎石环绕身躯。对任何试图攻击你的单位造成1点基于力场防御的物理-力场伤害。<br> 在维持土龙势时，可造成的伤害改为3点。<br> 在合适的情况下，精气熔流可能会破坏环境，比如或大地震荡使脆弱的墙壁倒塌（显然硬度3以上的墙壁不会受到伤害）。</p><p>山之力（Force of the Mountain）<br> 价格：D+750<br> 购买前提：武技3+<br> 类型：被动<br> 持续时间：立即<br> 前置秘法：无<br> 土龙流道徒从他大地中汲取力量，再将自己精气不断的分裂回归大地。当他触发【精气熔流】时，环绕身躯的土元之力将被强化，使武者获得等同于自身力量附加成功数量的立场防御。<br> 在极少数情况下，有些武者会钻研这个最为基础的入门技艺，直到武者与大地的连接犹如一体，回归完整的姿态，似石如山；一旦达成这一境界，只要武者脚踏大地便不会再衰老，这是C级【免疫衰老】与寿命不随时间流逝的效果，传闻中葛老以此活过了数个百年。</p><p>磐石当身（Stillness-of-Stone Atemi）<br> 价格：D+500<br> 消耗：1土灵精气<br> 购买前提：武技3+<br> 动作：整轮动作<br> 类型：主动<br> 持续时间：立即<br> 前置秘法：山之力（Force of the Mountain）<br> 土龙流道徒令敌人明白什么叫世界的重压。当他触发【精气熔流】时，大地将他托起。环绕的碎石将加固他的拳腿或武器锤头，令他释放更具有威力的一击。<br> 整轮动作使用，消耗1土灵精气结合在一次冲锋攻击中，大地猛然凸起将武者弹射至半空，弹射高度最高为武者基础移动距离的一半，而弹射的最大距离则等于武者最大移动距离*2；随后武者将直线跃向目标地点，挥动铁锤或双拳协同巨石向目标悍然压下。该次攻击中除了获得冲锋本该有的好处和劣势外，还将额外获得1点附加成功和4dp增强加值，额外获得的加值造成的伤害类型为：力场伤害。</p><p>滚石锤（Rolling Boulder Blow）<br> 价格：D+500<br> 消耗：1土灵精气<br> 购买前提：武技3+<br> 动作：标准动作+移动动作<br> 类型：主动<br> 持续时间：立即<br> 前置秘法：山之力（Force of the Mountain）<br> 土龙流道徒以无可撼动的力量将山岳击飞。<br> 当武者触发【精气熔流】时，可消耗1点土灵精气并移动动作踩踏地面，若如此做，则一块滚石便脱离地面在人物身边漂浮，如此获得的滚石体积等同于人物的力量附加成功数，并具有等同于自身体积点的武器伤害。滚石只会存在一轮，若未击发则在回合末无害崩解回归大地。<br> 当成功召唤滚石后，武者可以标准动作将滚石如同棒球般击向目标，视为一次投掷攻击，但依然使用力量+武技（拳/腿/长枪/棍/锤）进行检定，检定中获得3DP增强加值。</p><p>不动如山（Unmoving Mountain Stance）<br> 价格：D+500<br> 消耗：1土灵精气<br> 购买前提：武技3+<br> 动作：无。<br> 类型：被动<br> 持续时间：一轮<br> 前置秘法：山之力（Force of the Mountain）<br> 土龙流道徒拒绝向敌人屈服，绝不！<br> 当武者触发【精气熔流】的下一轮内，可移动动作消耗1点土灵精气进行一次肉搏/白刃格挡，在召唤出一面环绕自身的土墙、使得该次格挡额外获得5点立场防御。<br> 若武者愿意支付3点土灵精气和一点意志，那么土石会将武者完全包裹形成一个石球，则格挡防御加值改为5点立场防御+1点【封闭】，但显然的，在该状态下若武者自身不具有透视或类似能力，则会完全丢失视野，视距恒定为1米。<br> 武者可以自由动作将土墙或者石球无害消散，即使没有有意消除，这些土墙石球也会在持续超过一轮后因为失去土灵精气支持而无害的崩落，化作泥土石块。</p><p>土龙势（Earth Dragon Form）<br> 价格：C+1000<br> 购买前提：武技4+<br> 类型：架势<br> 动作：迅捷动作启用<br> 持续时间：一个场景<br> 前置秘法：山之力（Force of the Mountain）<br> 土龙流道徒的动作缓慢而从容，仿佛将空气如岩石般进行雕琢，没有聪明的办法，没有狡猾与刁钻，土龙流道徒必须直面他的敌人，勇敢和坚韧是对土龙流道徒最好的诠释。<br> 特殊激活规则：当武者双脚并未踩在地面上，可以强行消耗3点精气，激活土元之力进入【精气熔流】状态并持续一轮，在该状态下土灵精气无法恢复，直到你重现踏入地面为止。<br> 开启土龙势后，当武者对触及范围内的敌人攻击时，所有处于武者攻击范围内的敌人若被命中，除正常受到伤害外，还会土元之力所压制，如背负千钧重担一般，其移动速度将降低40米，最低为0，持续一轮。<br> 购买土龙势不会获得自由属性。</p><p>撼地猛击（Earthshaker Attack）<br> 价格：C+1000<br> 消耗：1土灵精气<br> 购买前提：武技4+<br> 类型：被动<br> 持续时间：立即<br> 前置秘法：土龙势（Earth Dragon Form）<br> 当土龙流道徒行走在地上时，大地随着他的力量而颤抖。<br> 武者维持土龙势的状态下，便可消耗1点土灵精气结合在任意一次攻击中；土龙流道徒狠狠顿足或是将铁锤砸在地上，大地开始震荡，石柱升起，土刺飞溅，对武者触及范围内所有敌方单位同时开展攻击；这使得该次攻击变为一次范围伤害，被影响目标需要以反射豁免，造成力场伤害。<br> 每轮一次，受到攻击影响的目标视为受到一次冲撞，对抗失败则倒地。<br> 石柱土刺会在回合结束后无害的消散，化为一地碎石。</p><p>地噬击（Hungry Earth Strike）<br> 价格：C+1000<br> 购买前提：武技4+<br> 消耗：1土灵精气<br> 类型：被动<br> 持续时间：立即<br> 前置秘法：无<br> 前置秘法：土龙势<br> 帕西亚普张开巨口，以锯齿状的裂缝将无瑕道徒的敌人吞噬。若他令在泥土、石头或类似平面上的敌人（或是敌人被强击撞到了这种平面上）倒地，敌人脚下的地面会将其吞没。<br> 土龙流道徒结合在进行结合在一次肉搏相关行为中使用本秘法，额外获得4米触及距离，武者重踏地面或用武器锤击大地，敌人脚下的土地登时开裂或化为流沙，将敌人吞没，除了不会占用角色的肢体以外，此检定和效果都被认为是角色自己进行了肉搏攻击或擒抱等检定，正常计算武器伤害。<br> 被土灵精气影响用作束缚的土地视为具有【法破】特性，无法被虚体等效果穿过逃离，由于单位会完全陷入地下并因此窒息，若无透视也会失去视觉距离（并非目盲），这是C级环境来源的效果。<br> 购买地噬击不会获得自由属性。</p><p>陨星冲（Crater-Making Impact）<br> 价格：B+2000<br> 消耗：1土灵精气<br> 购买前提：武技4+<br> 动作：特殊<br> 类型：主动<br> 持续时间：立即<br> 前置秘法：土龙势、磐石当身<br> 土龙流道徒感受尘世大地之下流动的地震之力，将其与自己的力量结合，跳至最高点后操控土石加重自身质量，如流星般坠落向敌人释放不可阻挡的毁灭的打击。<br> 使用此秘法必须结合在磐石当身的攻击中，若被攻击敌人处于肉搏/白刃格挡状态，或未能完全闪避该次攻击（攻击命中），你可以使那次攻击获得5DP增强加值，并用巨大的冲量将直接摧毁他的手臂。<br> 该次攻击将使得目标的上肢双臂直接陷入【肢体残障】状态，这是A级创伤来源的效果，持续一轮。<br> 宣称自己能够杀死巨山的傻瓜只有在自己双臂与佩剑粉碎时才会后悔。<br> 选开：若开启物品破坏规则，那么陨星冲将直接击毁无支线等级的普通兵器。</p><p>势如山崩（Avalanche Method）<br> 价格：A+4000<br> 消耗：2土灵精气<br> 购买前提：武技5+<br> 动作：整轮动作<br> 类型：主动<br> 持续时间：立即<br> 前置秘法：陨星冲<br> 武者一锤接一锤的狂猛攻击能将最傲慢的异教徒击至跪地。<br> 当武者成功的释放了一次陨星冲并击中对手，那么便可立即以自由动作消耗2点土灵精气以派生【势如山崩】。<br> 【势如山崩】<br> 武者在攻击落地后，立即进行一次不附带主动技艺的锤击/肉搏攻击。若武者在攻击的当轮维持土龙势，那么速度减少的效果将再额外提升你的力量附加*30米。<br> 购买势如山崩不会获得自由属性。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const u=a(p,[["render",s]]);export{f as __pageData,u as default};
